    logic [DATA_WIDTH-1:0] rd_rsp_cnt_q;

    assign rd_rsp_cnt_decode = (addr == (ADDR_OFFSET+'h0+'h208));
    assign rd_rsp_cnt_sw_wr = sw_wr && rd_rsp_cnt_decode;
    assign rd_rsp_cnt_sw_rd = sw_rd && rd_rsp_cnt_decode;

    always_comb begin
        rd_rsp_cnt_q = '0;
        rd_rsp_cnt_q[63: 0] = rd_rsp_cnt_dfx_cnt_q;
    end

    // masked version of return data
    assign rd_rsp_cnt_rdata = rd_rsp_cnt_sw_rd ? rd_rsp_cnt_q : 'b0;

    // ------------------------------------------------------------
    // Field: dfx_cnt (wire)
    // ------------------------------------------------------------
    assign rd_rsp_cnt_dfx_cnt_anded = & rd_rsp_cnt_dfx_cnt_q;
    assign rd_rsp_cnt_dfx_cnt_ored  = | rd_rsp_cnt_dfx_cnt_q;
    assign rd_rsp_cnt_dfx_cnt_xored = ^ rd_rsp_cnt_dfx_cnt_q;

    // next hardware value
    assign rd_rsp_cnt_dfx_cnt_next = rd_rsp_cnt_dfx_cnt_wdata;
    assign rd_rsp_cnt_dfx_cnt_q = rd_rsp_cnt_dfx_cnt_next;
            
        
    // ============================================================
    // Register: DFX_THRESHOLD0
    //    [31: 0]        dfx_threshold: hw=r     sw=rw    reset=0x0
    // ============================================================
    logic                  dfx_threshold0_decode;
    logic                  dfx_threshold0_sw_wr;
    logic                  dfx_threshold0_sw_rd;
    logic [DATA_WIDTH-1:0] dfx_threshold0_q;

    assign dfx_threshold0_decode = (addr == (ADDR_OFFSET+'h0+'h400));
    assign dfx_threshold0_sw_wr = sw_wr && dfx_threshold0_decode;
    assign dfx_threshold0_sw_rd = sw_rd && dfx_threshold0_decode;

    always_comb begin
        dfx_threshold0_q = '0;
        dfx_threshold0_q[31: 0] = dfx_threshold0_dfx_threshold_q;
    end

    // masked version of return data
    assign dfx_threshold0_rdata = dfx_threshold0_sw_rd ? dfx_threshold0_q : 'b0;

    // ------------------------------------------------------------
    // Field: dfx_threshold
    // ------------------------------------------------------------
    assign dfx_threshold0_dfx_threshold_anded = & dfx_threshold0_dfx_threshold_q;
    assign dfx_threshold0_dfx_threshold_ored  = | dfx_threshold0_dfx_threshold_q;
    assign dfx_threshold0_dfx_threshold_xored = ^ dfx_threshold0_dfx_threshold_q;

    // next hardware value

    //! main storage
    always_ff @ (posedge clk)
    if (rst) begin
        dfx_threshold0_dfx_threshold_q <= 64'd0;
        dfx_threshold0_dfx_threshold_swmod <= 1'b0;
    end else begin
        dfx_threshold0_dfx_threshold_swmod <= 1'b0;
        // Software write
        if (dfx_threshold0_sw_wr) begin
            dfx_threshold0_dfx_threshold_swmod <= 1'b1;
            dfx_threshold0_dfx_threshold_q <=  sw_masked_data[31: 0] | (dfx_threshold0_dfx_threshold_q & ~sw_mask[31: 0]);
        end
    end

endmodule: virtio_avail_ring_reg_dfx
